import requests
from requests.exceptions import RequestException

base = 'http://localhost:8080'
known = ['index.php','search.php','login.php']
# common source disclosure suffixes for known files
suffixes = ['.phps','~','.bak','.old','.save','.swp','.swo','.orig']
paths = []
for k in known:
    for s in suffixes:
        paths.append(f"/{k}{s}")

# also try direct .phps for base names
for name in ['index','search','login']:
    paths.append(f"/{name}.phps")

results = []
for p in paths:
    url = base + p
    try:
        r = requests.get(url, timeout=5)
        results.append((p, r.status_code, len(r.content)))
    except RequestException as e:
        results.append((p, 'ERR', str(e)[:60]))

# Print any with status 200 or small content that may be source
for p, code, ln in results:
    if code == 200:
        print(f"HIT {p} -> {code} bytes:{ln}")
